export class Game {
  private rolls: number[] = [];

  roll(pins: number): void {
    this.rolls.push(pins);
  }

  score(): number {
    let score = 0;
    let rollIndex = 0;

    for (let frame = 0; frame < 10; frame++) {
      // Check if it's a strike
      if (this.rolls[rollIndex] === 10) {
        // Strike: 10 + next two rolls
        score += 10 + this.rolls[rollIndex + 1] + this.rolls[rollIndex + 2];
        rollIndex++; // Move to next frame (strike uses only one roll)
      } 
      // Check if it's a spare
      else if (this.rolls[rollIndex] + this.rolls[rollIndex + 1] === 10) {
        // Spare: 10 + next roll
        score += 10 + this.rolls[rollIndex + 2];
        rollIndex += 2; // Move to next frame (spare uses two rolls)
      } 
      // Regular frame
      else {
        score += this.rolls[rollIndex] + this.rolls[rollIndex + 1];
        rollIndex += 2; // Move to next frame (regular frame uses two rolls)
      }
    }

    return score;
  }
}
